#include "KnobLookAndFeel.h"
namespace SonicForge { void KnobLookAndFeel::drawRotarySlider(juce::Graphics& g,int x,int y,int w,int h,float pos,float start,float end,juce::Slider& s){ auto b=juce::Rectangle<float>(x,y,w,h).reduced(12); auto radius=juce::jmin(b.getWidth(),b.getHeight())/2.f; auto c=b.getCentre(); auto angle=start+pos*(end-start); g.setColour(juce::Colour(0xff20242b)); g.fillEllipse(c.x-radius,c.y-radius,radius*2,radius*2); g.setColour(juce::Colour(0xff4c5260)); g.drawEllipse(c.x-radius,c.y-radius,radius*2,radius*2,2.f); g.setColour(juce::Colour(0xffe7c873)); juce::Path p; p.addRectangle(-2.f,-radius,4.f,radius*.45f); p.applyTransform(juce::AffineTransform::rotation(angle).translated(c)); g.fillPath(p); g.setColour(juce::Colour(0xffd7dbe4)); g.setFont(13.f); g.drawText(s.getName().toUpperCase(), x, y+h-20, w, 18, juce::Justification::centred); } }
